INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_diff_301','ネットワーク中心採用モデル（NETAM）','Network-Centric Adoption Model (NETAM)','社会ネットワーク分析とイノベーション普及理論を統合し、採用者の接続中心性・ブリッジポジション・コミュニティ埋め込み度が採用速度に与える影響を定式化したモデル。エゴネットワーク分析データを用いた実証研究が多数行われている。','ソーシャルマーケティング戦略のターゲティング精度向上と公共技術普及プログラムの設計に貢献した。','diffusion_adoption_user','C_processes','ネットワーク普及理論','2008','meso','diffusion','network_centrality_adoption','["Valente, T.W.", "Burt, R.S.", "Watts, D.J."]','["Valente (1996) Social network thresholds", "Burt (2004) Structural holes and good ideas"]','ネットワーク中心性,社会ネットワーク,採用モデル,ブリッジポジション','network centrality,social network,adoption model,bridge position'),
('inno_diff_302','採用後の技術組み込み（Embeddedness）研究','Post-Adoption Technology Embeddedness Research','ITシステムが組織プロセス・意思決定・関係性に深く組み込まれ（埋め込まれ）、切り替えコストが飛躍的に高まる現象を分析した研究群。Harrisonらの技術組み込みモデルとPCM（プロセス変化モデル）を基盤としている。','企業のITベンダー交渉力分析とロックイン設計・オープンスタンダード政策に貢献した。','diffusion_adoption_user','C_processes','継続使用・組み込み研究','2006','meso','adoption','embeddedness_adoption','["Karahanna, E.", "Agarwal, R.", "Angst, C.M."]','["Karahanna et al. (1999) User acceptance IS", "Angst & Agarwal (2009) Adoption EMR"]','技術組み込み,ロックイン,継続使用,切替コスト','technology embeddedness,lock-in,continued use,switching cost'),
('inno_diff_303','採用研究における測定不変性検証の方法論','Methodological Validation of Measurement Invariance in Adoption Research','TAM・UTAUTなど採用研究の測定モデルが国・文化・性別・年齢グループ間で測定不変性（configural/metric/scalar invariance）を満たすかを検証した方法論的研究群。多くの採用研究で測定不変性が確認されていないことを指摘し、クロスグループ比較の妥当性問題を提起した。','採用研究の方法論的厳密性向上と国際比較研究の設計改善に貢献した。','diffusion_adoption_user','C_processes','採用研究方法論','2015','micro','adoption','methodological_rigor','["Byrne, B.M.", "Cheung, G.W.", "Hair, J.F."]','["Byrne (2008) Structural equation modeling", "Cheung & Rensvold (2002) Measurement invariance"]','測定不変性,SEM,構造方程式,TAM方法論','measurement invariance,SEM,structural equation modeling,TAM methodology'),
('inno_diff_304','採用の非線形ダイナミクス研究（Sカーブとジャンプ）','Nonlinear Adoption Dynamics Research: S-Curves and Jumps','技術採用軌跡が単純なロジスティック曲線ではなく、断続的なジャンプ・プラトー・急落を含む複雑な非線形パターンを示す事例を分析した研究群。ネットワーク効果・プラットフォーム競争・制度変化が採用軌跡に不連続性をもたらすメカニズムを解明した。','技術予測精度の向上とプラットフォーム競争政策の設計に貢献した。','diffusion_adoption_user','C_processes','採用ダイナミクス研究','2005','meso','diffusion','nonlinear_adoption','["Christensen, C.M.", "Foster, R.N.", "Meade, N."]','["Foster (1986) Innovation: The attacker''s advantage", "Meade & Islam (2006) Modeling and forecasting diffusion"]','採用ダイナミクス,Sカーブ,非線形採用,普及予測','adoption dynamics,S-curve,nonlinear adoption,diffusion forecasting'),
('inno_diff_305','ジェンダーと技術採用の批判的研究','Critical Research on Gender and Technology Adoption','技術採用研究における性別差異の原因を、単純な態度差ではなく社会的ジェンダー規範・デザイン偏向・ステレオタイプ脅威から説明した研究群。STEM・IT採用・ゲーム技術などで女性の採用率が低い構造的原因を解明した。','DEI（多様性・公平性・包摂性）テクノロジー政策と採用研究の測定偏向是正に貢献した。','diffusion_adoption_user','C_processes','ジェンダー・技術採用研究','2000','micro','adoption','gender_bias_adoption','["Venkatesh, V.", "Morris, M.G.", "Trauth, E.M."]','["Venkatesh & Morris (2000) Gender IT adoption", "Trauth (2002) Odd girl out"]','ジェンダー,技術採用,DEI,ステレオタイプ脅威','gender,technology adoption,DEI,stereotype threat'),
('inno_diff_306','ルーラル地域のデジタル採用研究（農村情報格差）','Rural Digital Adoption Research: Information Divide in Rural Areas','農村地域住民によるインターネット・スマートフォン・電子政府サービス採用の阻害要因を分析した研究群。インフラ格差・デジタルリテラシー・コンテンツ関連性・農村文化規範が採用規定因として確認されている。','農村デジタルインクルージョン政策とブロードバンド投資計画に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルデバイド・農村研究','2005','meso','adoption','rural_digital_divide','["Salemink, K.", "Strijker, D.", "Bosworth, G."]','["Salemink et al. (2017) Rural digital economy", "Grubesic (2006) Spatial patterns broadband"]','農村デジタル採用,情報格差,ブロードバンド,デジタルインクルージョン','rural digital adoption,information divide,broadband,digital inclusion'),
('inno_diff_307','採用研究のシステマティックレビュー・レビュー方法論','Systematic Review Methodology in Adoption Research','TAM・UTAUT・イノベーション普及理論を対象としたシステマティックレビューとメタ分析の方法論を検討した研究群。出版バイアス・変数操作化の不統一・調整変数の扱いなど方法論的課題を体系的に整理した。','採用研究の累積知識を統合する方法論の改善と研究アジェンダ設定に貢献した。','diffusion_adoption_user','C_processes','採用研究方法論','2010','micro','adoption','systematic_review_method','["Venkatesh, V.", "Dwivedi, Y.K.", "Marangunić, N."]','["Marangunić & Granić (2015) TAM review", "Dwivedi et al. (2011) TAM meta-analysis"]','システマティックレビュー,メタ分析,TAMレビュー,採用研究方法論','systematic review,meta-analysis,TAM review,adoption research methodology'),
('inno_diff_308','感情と技術採用：快楽的・認知的二経路モデル','Emotion and Technology Adoption: Hedonic-Cognitive Dual Pathway Model','技術採用における感情（快楽的価値・楽しさ・美的魅力）と認知（有用性・利便性）の二経路が独立して採用意図に影響する構造を分析したモデル群。消費者向けアプリ・エンタメ技術での応用が特に蓄積されている。','UXデザインにおける感情設計の理論的根拠を提供し、ゲーム・ソーシャルメディア採用研究を発展させた。','diffusion_adoption_user','C_processes','感情的採用研究','2007','micro','adoption','hedonic_cognitive_dual_path','["Van der Heijden, H.", "Brown, S.A.", "Venkatesh, V."]','["Van der Heijden (2004) Hedonic IS", "Brown & Venkatesh (2005) Consumer technology model"]','感情的採用,快楽的価値,二経路モデル,UXデザイン','emotional adoption,hedonic value,dual pathway model,UX design'),
('inno_diff_309','組織間知識移転と採用：Cohesion vs. Structural Holesの比較','Inter-Organizational Knowledge Transfer and Adoption: Cohesion vs. Structural Holes Comparison','組織間ネットワークにおける知識移転型採用を、強い紐帯（凝集型）とBurt的構造的穴（橋渡し型）の二つのアプローチから比較分析した研究群。どちらのネットワーク構造がイノベーション採用を促進するかを文脈依存的に説明した。','ナレッジマネジメント戦略とイノベーションネットワーク設計に理論的根拠を提供した。','diffusion_adoption_user','C_processes','組織間採用・ネットワーク研究','2004','meso','adoption','knowledge_transfer_adoption','["Burt, R.S.", "Coleman, J.S.", "Inkpen, A.C."]','["Burt (2004) Structural holes and good ideas", "Coleman (1988) Social capital in creation of human capital"]','組織間知識移転,構造的穴,凝集型ネットワーク,採用促進','inter-organizational knowledge transfer,structural holes,cohesion,adoption promotion'),
('inno_diff_310','地域医療情報共有ネットワーク採用研究','Health Information Exchange Adoption Research','HIE（医療情報交換）ネットワークへの病院・診療所の参加採用を分析した研究群。利害関係者間のインセンティブ不整合・データ標準化・プライバシー規制・競合関係にある病院間の情報共有抵抗が主要障壁として確認されている。','医療情報政策と地域医療連携システム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ヘルスIT採用研究','2009','meso','adoption','inter_hospital_adoption','["Adler-Milstein, J.", "Bates, D.W.", "Jha, A.K."]','["Adler-Milstein et al. (2011) HIE adoption", "Jha et al. (2009) EHR adoption hospitals"]','医療情報共有,HIE,電子カルテ,病院間連携','health information exchange,HIE,EHR,inter-hospital collaboration'),
('inno_diff_311','ゲームストリーミングサービス採用研究（クラウドゲーミング）','Cloud Gaming Service Adoption Research','Google Stadia・Xbox Cloud Gaming・GeForce NOWなどクラウドゲーミングサービスへの採用を分析した研究群。入力遅延（レイテンシ）・映像品質・ゲームライブラリ・所有権感覚の喪失が採用障壁として確認されている。','ゲーム産業のクラウド移行戦略と5G/6Gインフラ投資政策に貢献した。','diffusion_adoption_user','C_processes','クラウドゲーミング採用研究','2019','micro','adoption','latency_adoption_barrier','["Huang, C.Y.", "Hsu, Y.L.", "Eisenmann, T.R."]','["Huang et al. (2019) Cloud gaming adoption", "Eisenmann et al. (2006) Platform envelopment"]','クラウドゲーミング,ストリーミング,レイテンシ,ゲーム採用','cloud gaming,streaming,latency,game adoption'),
('inno_diff_312','デジタル工芸・メーカームーブメントの採用研究','Adoption Research on Digital Craft and Maker Movement','3Dプリンター・レーザーカッター・Arduino・Raspberry Piなどデジタルファブリケーションツールへの個人・コミュニティ採用（メーカームーブメント）を分析した研究群。趣味的動機・コミュニティ帰属感・工具アクセスが採用規定因として確認されている。','メーカースペース政策と教育技術リテラシー育成に実証的根拠を提供した。','diffusion_adoption_user','C_processes','メーカームーブメント採用研究','2012','micro','adoption','maker_community_adoption','["Anderson, C.", "Hatch, M.", "Halverson, E.R."]','["Anderson (2012) Makers", "Hatch (2013) Maker Movement Manifesto"]','メーカームーブメント,デジタルファブリケーション,3Dプリンター,DIY採用','maker movement,digital fabrication,3D printer,DIY adoption'),
('inno_diff_313','資産管理・ウェルス管理テクノロジー採用研究','Wealth Management Technology Adoption Research','ロボアドバイザー・デジタル資産管理プラットフォーム・ESGスクリーニングツールへの個人投資家・機関投資家採用を分析した研究群。投資パフォーマンス期待・信頼・アルゴリズム透明性・人的アドバイスの代替可能性認識が採用規定因として確認されている。','フィンテック投資サービス規制と金融機関のデジタル変革戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','フィンテック・ウェルスマネジメント採用研究','2016','micro','adoption','algorithm_trust_adoption','["Phoon, K.", "Koh, F.", "Fisch, C."]','["Phoon & Koh (2018) Robo-advisors", "Fisch et al. (2021) Robo-advice adoption"]','ロボアドバイザー,ウェルスマネジメント,アルゴリズム信頼,デジタル投資','robo-advisor,wealth management,algorithm trust,digital investment'),
('inno_diff_314','農業ドローン採用の途上国研究','Agricultural Drone Adoption in Developing Countries','アフリカ・東南アジア・南米での農業用ドローン（農薬散布・作物モニタリング）採用を分析した研究群。輸入コスト・部品調達困難・パイロット訓練・規制整備が採用障壁として確認されている。ルワンダなど先進的規制実験の事例も研究されている。','途上国の農業機械化政策とドローン産業の新興国展開戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','農業テクノロジー採用研究（途上国）','2017','meso','adoption','cost_access_adoption','["Watts, L.", "Li, H.", "Rejeb, A."]','["Rejeb et al. (2022) Drones in agriculture", "Li et al. (2021) Drone adoption Asia"]','農業ドローン,途上国採用,農薬散布,農業機械化','agricultural drone,developing countries,pesticide spraying,farm mechanization'),
('inno_diff_315','ロボット過程自動化（RPA）採用の財務部門研究','Finance Department Research on Robotic Process Automation Adoption','経理・財務報告・内部監査・コンプライアンスチェックでのRPA採用を分析した研究群。プロセス標準化度・経営陣支持・IT部門との協働・継続メンテナンスコストが採用規定因として確認されている。CFOの意思決定プロセス分析も含まれる。','財務DXと会計士のスキル転換戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','RPA採用研究','2018','meso','adoption','process_automation_adoption','["van der Aalst, W.", "Lacity, M.", "Willcocks, L."]','["Lacity & Willcocks (2016) RPA at work", "van der Aalst (2018) Process mining"]','RPA,ロボット過程自動化,財務DX,プロセス標準化','RPA,robotic process automation,finance DX,process standardization'),
('inno_diff_316','ヘルスケアウェアラブル採用の慢性疾患患者研究','Chronic Disease Patient Research on Healthcare Wearable Adoption','糖尿病・高血圧・心疾患患者による連続血糖測定・心電図ウォッチ・血圧モニター採用を分析した研究群。疾患管理自己効力感・医師との共有動機・データ疲れ・デバイス不快感が採用規定因として確認されている。','慢性疾患管理プログラム設計と遠隔患者モニタリング政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','慢性疾患ウェアラブル採用研究','2016','micro','adoption','self_management_adoption','["Schroeder, J.", "Epstein, D.A.", "Klasnja, P."]','["Schroeder et al. (2017) Wearable chronic disease", "Epstein et al. (2015) Lived informatics"]','慢性疾患,ウェアラブル採用,連続血糖測定,遠隔モニタリング','chronic disease,wearable adoption,continuous glucose monitoring,remote monitoring'),
('inno_diff_317','テキストマイニング・NLPツール採用の研究者研究','Researcher Adoption of Text Mining and NLP Tools','学術研究者によるVOSviewer・NLTK・BERTopic・SciBERT採用を分析した研究群。ドメイン知識と技術スキルのギャップ・ツール互換性・文献管理システムとの統合が採用規定因として確認されている。','学術研究方法論の計算論的転換（computational turn）推進に実証的根拠を提供した。','diffusion_adoption_user','C_processes','研究ツール採用研究','2018','micro','adoption','skill_gap_adoption','["Blei, D.M.", "Van Eck, N.J.", "Waltman, L."]','["Blei et al. (2003) LDA", "Van Eck & Waltman (2010) VOSviewer"]','テキストマイニング,NLP,研究ツール採用,計算論的研究','text mining,NLP,research tool adoption,computational research'),
('inno_diff_318','コミュニティ主導型採用モデル（CLAM）','Community-Led Adoption Model (CLAM)','普及エージェント主導ではなく、地域コミュニティ内の自発的チャンピオンと非公式ネットワークが採用を牽引する「コミュニティ主導型採用」を理論化したモデル。ピアチャンピオン効果・コミュニティ信頼・文化的適合性が中核概念となっている。','農村開発・公衆衛生・コミュニティテクノロジー普及プログラムに理論的根拠を提供した。','diffusion_adoption_user','C_processes','コミュニティ採用理論','2010','meso','diffusion','community_champion_adoption','["Dearing, J.W.", "Kreuter, M.W.", "Green, L.W."]','["Dearing (2009) Applying diffusion of innovation theory", "Kreuter & Bernhardt (2009) Reframing diffusion"]','コミュニティ採用,ピアチャンピオン,非公式ネットワーク,文化的適合性','community adoption,peer champion,informal network,cultural fit'),
('inno_diff_319','デジタルヘルスコーチング採用研究','Digital Health Coaching Adoption Research','AIコーチング・行動変容チャットボット・オンライン生活習慣改善プログラムへの採用を分析した研究群。信頼性・共感性・個人化・行動変容理論との整合性が採用規定因として確認されている。ハイブリッド型（AI+人間コーチ）の採用優位性も研究されている。','予防医療政策とヘルスケアAIの設計原則に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルヘルスコーチング研究','2017','micro','adoption','personalization_adoption','["Torous, J.", "Firth, J.", "Mohr, D.C."]','["Torous & Hsin (2018) Digital health coaching", "Mohr et al. (2017) Personal sensing mental health"]','デジタルヘルスコーチング,行動変容AI,予防医療,個人化','digital health coaching,behavior change AI,preventive medicine,personalization'),
('inno_diff_320','食品配達サービス採用研究（フードデリバリーアプリ）','Food Delivery App Adoption Research','Uber Eats・Deliveroo・出前館・Meituan Waimai等フードデリバリーアプリへの採用を分析した研究群。利便性・配達時間・価格・飲食店多様性・配達員評価システムが採用規定因として確認されている。','フードデリバリー産業のプラットフォーム設計と飲食業デジタル変革戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','フードデリバリー採用研究','2018','micro','adoption','convenience_adoption','["Yeo, V.C.S.", "Goh, S.K.", "Rezaei, S."]','["Yeo et al. (2017) Online food delivery adoption", "Rezaei et al. (2016) Online impulse buying"]','フードデリバリー,Uber Eats,利便性採用,配達アプリ','food delivery,Uber Eats,convenience adoption,delivery app'),
('inno_diff_321','デジタルツイン採用の都市管理研究','Urban Management Research on Digital Twin Adoption','都市インフラ（交通・水道・電力・建物）のデジタルツイン採用を分析した研究群。都市行政のデジタル能力・民間パートナーとのデータ共有ガバナンス・ROI可視化困難が採用規定因として確認されている。シンガポール・ヘルシンキの先進事例研究が蓄積されている。','スマートシティ政策とデジタルインフラ管理の国際標準設計に貢献した。','diffusion_adoption_user','C_processes','スマートシティ採用研究','2018','meso','adoption','urban_data_adoption','["Batty, M.", "Dembski, S.", "Krook, J."]','["Batty (2018) Digital twins cities", "Dembski et al. (2020) Urban digital twins"]','都市デジタルツイン,スマートシティ管理,都市インフラ,データガバナンス','urban digital twin,smart city management,urban infrastructure,data governance'),
('inno_diff_322','開発者向け低コード・ノーコードプラットフォーム採用','Low-Code/No-Code Platform Adoption Among Developers and Citizen Developers','OutSystems・Microsoft Power Apps・Bubble等低コード/ノーコードプラットフォームへのIT専門家および市民開発者の採用を分析した研究群。開発速度・柔軟性制限・ガバナンス不安・影の IT（Shadow IT）リスクが採用規定因として確認されている。','企業のアプリ開発民主化戦略とIT部門の役割変容研究に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ローコード採用研究','2019','meso','adoption','citizen_developer_adoption','["Richardson, C.", "Vincent, P.", "Peffers, K."]','["Richardson (2021) Low-code future", "Vincent & Isaksson (2022) Low-code adoption"]','ローコード,ノーコード,市民開発者,Shadow IT','low-code,no-code,citizen developer,shadow IT'),
('inno_diff_323','スマート農業採用における農家のデータ信頼研究','Farmer Data Trust Research in Smart Agriculture Adoption','アグリテックプラットフォームが収集する農場データの農家への帰属・利用目的・プライバシーへの農家の信頼と疑念が採用を規定する構造を分析した研究群。データ主権・農家-企業間の力関係・データ取引の透明性が主要テーマとなっている。','農業データガバナンス政策と農業技術企業のデータ倫理設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','農業データ信頼採用研究','2019','micro','adoption','data_sovereignty_adoption','["Jakku, E.", "Taylor, B.", "Fleming, A."]','["Jakku et al. (2019) Farmer data trust", "Fleming et al. (2018) Data sharing agriculture"]','農業データ信頼,データ主権,アグリテック,農家データ','agricultural data trust,data sovereignty,agritech,farmer data'),
('inno_diff_324','ランドフィルガスエネルギー採用研究','Landfill Gas Energy Adoption Research','埋立地ガス（LFG）の回収・発電技術の採用を廃棄物処理業者・自治体・電力会社の視点から分析した研究群。規制インセンティブ・技術学習コスト・炭素クレジット収益性が採用規定因として確認されている。','廃棄物エネルギー政策と循環経済推進戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','廃棄物エネルギー採用研究','2005','meso','adoption','regulatory_incentive_adoption','["Cho, H.H.", "Jeong, S.", "Spokas, K.A."]','["Spokas et al. (2006) Landfill gas emissions", "Cho & Jeong (2020) LFG adoption review"]','埋立地ガス,廃棄物エネルギー,LFG,循環経済','landfill gas,waste energy,LFG,circular economy'),
('inno_diff_325','デジタル遺産・デジタル死後サービス採用研究','Digital Legacy and Post-Mortem Service Adoption Research','デジタル遺産管理・死後SNSアカウント・AIによる故人再現サービスへの消費者採用を分析した研究群。死の不安・プライバシー・家族同意・宗教的規範が採用態度に影響することが示された。タナテクノロジー（死のテクノロジー）という新分野を形成している。','デジタル資産相続法・遺族サービス設計・AI倫理規制に貢献した。','diffusion_adoption_user','C_processes','タナテクノロジー採用研究','2019','micro','adoption','mortality_salience_adoption','["Bassett, D.J.", "Kasket, E.", "Sofka, A."]','["Bassett (2015) Who owns your digital legacy", "Kasket (2019) All the Ghosts in the Machine"]','デジタル遺産,タナテクノロジー,AIデジタル死後,プライバシー','digital legacy,thanatechnology,AI afterlife,privacy'),
('inno_diff_326','量子センサー採用の産業研究','Industrial Research on Quantum Sensor Adoption','原子時計・重力センサー・量子磁力計など量子センサー技術の産業採用を分析した研究群。精度・コスト・操作環境制約・標準化不足が採用規定因として確認されている。防衛・資源探査・航法分野での初期採用事例が蓄積されている。','量子産業政策と精密計測技術の商業化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','量子技術採用研究','2020','meso','adoption','precision_technology_adoption','["Degen, C.L.", "Reinhard, F.", "Cappellaro, P."]','["Degen et al. (2017) Quantum sensing review", "Cappellaro (2014) NV center quantum sensing"]','量子センサー,精密計測,量子技術採用,産業応用','quantum sensor,precision measurement,quantum technology adoption,industrial application'),
('inno_diff_327','モバイル型医療診断デバイス採用研究（Point-of-Care）','Point-of-Care Mobile Diagnostic Device Adoption Research','POCT（ポイントオブケア検査）・超音波スマートフォン接続デバイス・在宅診断キットへの医療従事者・患者採用を分析した研究群。診断精度・校正手続き・規制承認・EHRシステム統合が採用規定因として確認されている。','低資源環境での診断アクセス拡大政策と遠隔医療設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','POCT採用研究','2014','micro','adoption','diagnostic_access_adoption','["Drain, P.K.", "Hyle, E.P.", "Mugabi, P."]','["Drain et al. (2014) Point-of-care diagnostics", "Mugabi et al. (2020) mHealth diagnostics Uganda"]','POCT,ポイントオブケア,モバイル診断,在宅検査','POCT,point-of-care,mobile diagnostics,home testing'),
('inno_diff_328','学術論文管理ツール採用の研究者研究','Researcher Adoption of Reference Management Tools','Zotero・Mendeley・EndNote・PaperpileへのPh.D.学生・研究者採用を分析した研究群。インポート自動化・共有機能・フォーマット互換性・無料版の機能制限が採用規定因として確認されている。','学術図書館サービス設計と研究生産性向上プログラムに実証的根拠を提供した。','diffusion_adoption_user','C_processes','研究ツール採用研究','2010','micro','adoption','academic_tool_adoption','["Francese, E.", "Mueller, A.B.", "Childress, M.D."]','["Childress (2011) Reference management comparison", "Francese (2013) Citation management survey"]','文献管理ツール,Zotero,Mendeley,研究者採用','reference management,Zotero,Mendeley,researcher adoption'),
('inno_diff_329','スポーツアナリティクス採用のプロスポーツ研究','Professional Sports Research on Sports Analytics Adoption','MLB・NBA・サッカー・ラグビーでのデータ分析・トラッキングシステム採用を分析した研究群。コーチ-アナリスト間の文化的衝突・スカウト伝統との緊張・選手プライバシーが採用規定因として確認されている。「Moneyball効果」の普及研究も含まれる。','スポーツフロント運営の意思決定改革とスポーツ科学の実践化に貢献した。','diffusion_adoption_user','C_processes','スポーツアナリティクス採用研究','2012','meso','adoption','data_culture_adoption','["Lewis, M.", "Alamar, B.", "Franks, A."]','["Lewis (2003) Moneyball", "Alamar (2013) Sports Analytics"]','スポーツアナリティクス,Moneyball,トラッキング,スポーツデータ採用','sports analytics,Moneyball,tracking,sports data adoption'),
('inno_diff_330','公共交通デジタル決済採用研究','Public Transit Digital Payment Adoption Research','ICカード・QRコード乗車・スマートフォン交通IC決済への通勤者採用を分析した研究群。乗り継ぎ利便性・残額管理・プライバシー・交通弱者への配慮が採用規定因として確認されている。','公共交通デジタル化政策とモビリティサービス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','公共交通採用研究','2012','micro','adoption','transit_convenience_adoption','["Currie, G.", "Ahern, A.", "Kim, K."]','["Currie (2010) Contactless ticketing", "Ahern & Anantatmula (2010) Transit smartcard"]','公共交通ICカード,QRコード乗車,交通IC決済,モビリティデジタル化','public transit IC card,QR code transit,transportation payment,mobility digitalization'),
('inno_diff_331','スマートホームエネルギー管理システム採用研究','Smart Home Energy Management System Adoption Research','HEMS（家庭用エネルギー管理システム）・スマートサーモスタット（Nest等）・蓄電池連携システムへの家庭採用を分析した研究群。節電インセンティブ・使いやすさ・設置複雑性・プライバシー懸念が採用規定因として確認されている。','家庭エネルギー政策と電力会社のデジタル需要管理戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマートエネルギー採用研究','2014','micro','adoption','energy_saving_adoption','["Darby, S.", "Kavousian, A.", "Fischer, C."]','["Darby (2006) Smart metering", "Kavousian et al. (2013) Determinants electricity use"]','HEMS,スマートサーモスタット,家庭省エネ,需要管理','HEMS,smart thermostat,home energy saving,demand management'),
('inno_diff_332','NFT採用とデジタル資産所有感研究','NFT Adoption and Digital Asset Ownership Research','Non-Fungible Token（NFT）へのコレクター・アーティスト・ゲーマー採用を分析した研究群。希少性知覚・コミュニティ帰属感・投機的動機・ブロックチェーン技術理解が採用規定因として確認されている。市場崩壊後の離脱行動研究も含まれる。','デジタル資産規制・クリエイターエコノミー政策・メタバース設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','NFT・デジタル資産採用研究','2021','micro','adoption','speculative_community_adoption','["Chohan, U.W.", "Sharma, T.", "Ante, L."]','["Chohan (2021) Non-fungible tokens", "Ante (2022) NFT market"]','NFT,デジタル資産,ブロックチェーン,コレクター採用','NFT,digital assets,blockchain,collector adoption'),
('inno_diff_333','企業向けメタバースプラットフォーム採用研究','Enterprise Metaverse Platform Adoption Research','Microsoft Mesh・Horizon Workrooms・Spatial等企業向けメタバース/VR会議ツールへの組織採用を分析した研究群。インターネット帯域・HMDデバイス不快感・ユースケースの不明確さ・ROI測定困難が採用障壁として確認されている。','企業の次世代コラボレーション戦略とメタバース政策形成に実証的根拠を提供した。','diffusion_adoption_user','C_processes','メタバース採用研究','2022','meso','adoption','virtual_collaboration_adoption','["Mystakidis, S.", "Dwivedi, Y.K.", "Hughes, L."]','["Mystakidis (2022) Metaverse overview", "Dwivedi et al. (2022) Metaverse beyond hype"]','メタバース,VR会議,企業採用,没入型コラボレーション','metaverse,VR meetings,enterprise adoption,immersive collaboration'),
('inno_diff_334','水素エネルギー採用の産業・輸送研究','Hydrogen Energy Adoption in Industry and Transportation','グリーン水素製造・燃料電池自動車・水素ステーション・工業プロセス水素化への企業採用を分析した研究群。コスト低減経路・インフラ整備タイミング・国際標準化・安全知覚が採用規定因として確認されている。','水素エネルギー産業政策と脱炭素技術ロードマップ設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','水素エネルギー採用研究','2019','meso','adoption','infrastructure_readiness_adoption','["Dawood, F.", "Anda, M.", "Shafiullah, G.M."]','["Dawood et al. (2020) Green hydrogen economy", "Shafiullah et al. (2022) Hydrogen adoption review"]','グリーン水素,燃料電池,水素エネルギー採用,脱炭素','green hydrogen,fuel cell,hydrogen energy adoption,decarbonization'),
('inno_diff_335','研究データ管理ツール採用の学術機関研究','Academic Institution Research on Research Data Management Tool Adoption','DMP（データ管理計画）作成ツール・データリポジトリ・研究データ共有プラットフォームへの研究者採用を分析した研究群。義務化政策（EU Horizon・NIH）による強制採用効果・データキュレーション負担・ドメイン別規範差異が採用規定因として確認されている。','研究データ政策・オープンサイエンス推進・データ共有インフラ整備に実証的根拠を提供した。','diffusion_adoption_user','C_processes','研究データ管理採用研究','2013','meso','adoption','mandate_driven_adoption','["Borgman, C.L.", "Whyte, A.", "Parsons, T."]','["Borgman (2015) Big Data Little Data", "Whyte & Tedds (2011) Making the case for RDM"]','研究データ管理,DMP,データリポジトリ,オープンサイエンス','research data management,DMP,data repository,open science'),
('inno_diff_336','配送ロボット採用の消費者研究','Consumer Research on Delivery Robot Adoption','Starship・Nuro・Amazon Scoutなど自律走行型配送ロボットへの消費者採用を分析した研究群。利便性・安全知覚・歩道通行への配慮・配送時間精度が採用規定因として確認されている。大学キャンパス・住宅地での実証実験データも蓄積されている。','ラストマイル物流革新政策と自律型ロボット規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','配送ロボット採用研究','2018','micro','adoption','autonomous_delivery_adoption','["Jennings, D.", "Figliozzi, M.", "Boysen, N."]','["Jennings & Figliozzi (2019) Delivery robots", "Boysen et al. (2021) Last mile delivery robots"]','配送ロボット,ラストマイル配送,自律走行,消費者採用','delivery robot,last mile delivery,autonomous delivery,consumer adoption'),
('inno_diff_337','量子インターネット採用の初期市場研究','Early Market Research on Quantum Internet Adoption','量子鍵配送（QKD）ネットワーク・量子テレポーテーション通信への政府・金融機関採用を分析した探索的研究群。技術成熟度・インフラ整備費用・暗号アジリティ移行・国際標準化が採用規定因として確認されている。','量子通信インフラ政策と次世代サイバーセキュリティ投資計画に初期知見を提供した。','diffusion_adoption_user','C_processes','量子通信採用研究','2021','meso','adoption','quantum_network_adoption','["Wehner, S.", "Elkouss, D.", "Hanson, R."]','["Wehner et al. (2018) Quantum internet roadmap", "Kozlowski & Wehner (2019) Towards quantum internet"]','量子インターネット,QKD,量子通信,量子セキュリティ','quantum internet,QKD,quantum communication,quantum security'),
('inno_diff_338','倫理的AI採用フレームワークの実証研究','Empirical Research on Ethical AI Adoption Frameworks','EU AI Act・NIST AI RMF・IEEE Ethically Aligned Designなど倫理的AIフレームワークの企業採用を分析した研究群。フレームワーク実装コスト・法的不確実性・競争上の不利益懸念・担当者不足が採用障壁として確認されている。','AI規制政策の実効性評価と企業ガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AI倫理採用研究','2021','meso','adoption','regulatory_compliance_ai','["Jobin, A.", "Fjeld, M.", "Rességuier, A."]','["Jobin et al. (2019) Global AI ethics landscape", "Fjeld et al. (2020) Principled AI"]','倫理的AI,AI Act,AI RMF,企業AI採用','ethical AI,AI Act,AI RMF,enterprise AI adoption'),
('inno_diff_339','コモンズ型デジタルインフラ採用研究','Digital Commons Infrastructure Adoption Research','Wikipedia・OpenStreetMap・IPFS・分散型ウェブ（DWeb）など共有デジタルインフラへの参加採用を分析した研究群。コモンズ管理論（Ostrom）を援用し、ルール認知・貢献互恵性・ガバナンス透明性が採用継続に影響することが示された。','デジタルコモンズ政策とオープンインフラへの公的投資戦略に理論的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルコモンズ採用研究','2011','meso','adoption','commons_governance_adoption','["Ostrom, E.", "Benkler, Y.", "Forte, A."]','["Ostrom (1990) Governing the commons", "Benkler (2006) Wealth of Networks"]','デジタルコモンズ,Wikipedia,OpenStreetMap,共有インフラ','digital commons,Wikipedia,OpenStreetMap,shared infrastructure'),
('inno_diff_340','採用後のアイデンティティ変容研究','Post-Adoption Identity Transformation Research','技術採用後に利用者の自己認識・社会的アイデンティティ・職業的アイデンティティが変容するプロセスを分析した研究群。Giddens の構造化理論・Tajfelの社会的アイデンティティ理論をIT採用文脈に適用した。','組織変革管理と人事育成プログラムの設計に理論的根拠を提供した。','diffusion_adoption_user','C_processes','採用後アイデンティティ研究','2008','micro','adoption','identity_transformation_adoption','["Orlikowski, W.J.", "Giddens, A.", "Tajfel, H."]','["Orlikowski (2000) Using technology", "Tajfel & Turner (1979) Social identity theory"]','アイデンティティ変容,技術採用後,自己認識,構造化理論','identity transformation,post-adoption,self-concept,structuration theory'),
('inno_diff_341','AI推薦システムの消費者採用研究','Consumer Adoption Research on AI Recommendation Systems','Netflix・Amazon・Spotify等AI推薦エンジンへの消費者採用と信頼・プライバシー認識を分析した研究群。推薦精度・説明可能性・フィルターバブル懸念・データ提供意欲が採用規定因として確認されている。','AI推薦システムのUX設計と個人データ規制（GDPR等）に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AI推薦採用研究','2017','micro','adoption','algorithmic_trust_adoption','["Knijnenburg, B.P.", "Willemsen, M.C.", "Gantner, Z."]','["Knijnenburg et al. (2012) Explaining recommendations", "Willemsen et al. (2016) RS adoption"]','AI推薦,推薦システム,フィルターバブル,説明可能性','AI recommendation,recommender system,filter bubble,explainability'),
('inno_diff_342','バイオメトリクス採用のセキュリティ研究','Security Research on Biometric Adoption','指紋・顔認証・虹彩・声紋認証などバイオメトリクスへの消費者・組織採用を分析した研究群。偽陽性率・生体情報漏洩不安・利便性・法的規制が採用規定因として確認されている。FALSEネガティブ不満と採用継続の関係も研究されている。','バイオメトリクス規制政策と認証システム設計の改善に実証的根拠を提供した。','diffusion_adoption_user','C_processes','生体認証採用研究','2013','micro','adoption','biometric_trust_adoption','["Bhatta, R.C.", "Jain, A.K.", "De Luca, A."]','["Jain et al. (2011) Biometrics overview", "De Luca et al. (2015) Authentication methods"]','バイオメトリクス,顔認証,指紋認証,生体情報セキュリティ','biometrics,face recognition,fingerprint,biometric security'),
('inno_diff_343','環境DNA（eDNA）技術採用の保全生態学研究','Conservation Ecology Research on eDNA Technology Adoption','環境水・土壌・空気中DNAを用いた生物多様性モニタリング技術への環境省・自然保護機関・企業採用を分析した研究群。検出精度・サンプリングプロトコル標準化・コストパフォーマンスが採用規定因として確認されている。','生物多様性政策（昆明-モントリオール目標）と環境アセスメント手法の近代化に貢献した。','diffusion_adoption_user','C_processes','環境技術採用研究','2017','meso','adoption','scientific_adoption','["Rees, H.C.", "Biggs, J.", "Taberlet, P."]','["Rees et al. (2014) eDNA freshwater", "Taberlet et al. (2018) Environmental DNA"]','環境DNA,eDNA,生物多様性モニタリング,保全生態学','environmental DNA,eDNA,biodiversity monitoring,conservation ecology'),
('inno_diff_344','スマートグラス採用の産業現場研究','Industrial Field Research on Smart Glasses Adoption','Google Glass Enterprise・RealWear・Vuzix等スマートグラスの製造・物流・フィールドサービス採用を分析した研究群。視野干渉・長時間装着不快感・手順情報表示精度・バッテリー持続が採用規定因として確認されている。','製造業の現場DX戦略と産業用ARデバイス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','産業用AR採用研究','2016','meso','adoption','hands_free_adoption','["Dünser, A.", "Grasset, R.", "Billinghurst, M."]','["Dünser et al. (2008) AR usability", "Billinghurst & Dünser (2012) AR interfaces"]','スマートグラス,産業用AR,Google Glass,現場DX','smart glasses,industrial AR,Google Glass,field DX'),
('inno_diff_345','消費者リサーチツール（市場調査AI）採用研究','Consumer Research Tool Adoption: Market Research AI','AIアンケート設計ツール・消費者インサイトAI・オンラインパネル・センチメント分析ツールへのマーケティングリサーチャー採用を分析した研究群。データ品質・AIバイアス懸念・ROI可視化・既存プロセス統合が採用規定因として確認されている。','マーケティングリサーチ産業のデジタル変革と調査倫理標準設計に貢献した。','diffusion_adoption_user','C_processes','マーケティングリサーチ採用研究','2018','micro','adoption','data_quality_adoption','["Blurton, C.", "Sparrow, N.", "Tourangeau, R."]','["Sparrow (2007) Online research", "Tourangeau et al. (2013) Survey methodology"]','市場調査AI,アンケートツール,マーケティングリサーチ,センチメント分析','market research AI,survey tools,marketing research,sentiment analysis'),
('inno_diff_346','ダイナミックプライシング採用の消費者研究','Consumer Research on Dynamic Pricing Adoption','Uberサージプライシング・ホテル収益管理・航空運賃・スポーツチケットのダイナミックプライシングへの消費者受容を分析した研究群。価格公平性認知・価格予測可能性・透明性・価格比較行動が受容規定因として確認されている。','収益管理戦略と価格規制政策の科学的根拠を提供した。','diffusion_adoption_user','C_processes','ダイナミックプライシング採用研究','2016','micro','adoption','price_fairness_adoption','["Xia, L.", "Monroe, K.B.", "Anderson, E.T."]','["Xia et al. (2004) The price is unfair", "Anderson & Wilson (2011) Dynamic pricing"]','ダイナミックプライシング,価格公平性,収益管理,Uberサージ','dynamic pricing,price fairness,revenue management,Uber surge'),
('inno_diff_347','ChatGPTと生成AI採用の組織・個人研究（2023年以降）','Organizational and Individual Research on ChatGPT and Generative AI Adoption Post-2023','ChatGPT・Gemini・Claude・Copilot等生成AIの急速普及後の組織・個人採用行動を分析した研究群。生産性効果の実証・プロンプトエンジニアリングスキルの重要性・ハルシネーション懸念・AI利用ポリシーの整備が主要テーマとなっている。','企業のAI活用戦略とAI教育政策の設計に実証的根拠を提供している最前線研究群。','diffusion_adoption_user','C_processes','生成AI採用研究','2023','micro','adoption','generative_ai_adoption','["Noy, S.", "Zhang, W.", "Brybrynjolfsson, E."]','["Noy & Zhang (2023) Experimental evidence ChatGPT", "Brynjolfsson et al. (2023) GenAI workplace"]','ChatGPT,生成AI採用,プロンプトエンジニアリング,ハルシネーション','ChatGPT,generative AI adoption,prompt engineering,hallucination'),
('inno_diff_348','デジタルピル採用研究（内蔵センサー錠剤）','Digital Pill Adoption Research: Ingestible Sensor Tablets','服薬確認センサーを内蔵したデジタルピル（Abilify MyCite等）の精神科・慢性疾患患者への採用を分析した研究群。プライバシー侵害懸念・自律性喪失・強制服薬への倫理的懸念が主要障壁として確認されている。患者の権利と医療モニタリングの緊張関係が重要テーマとなっている。','服薬管理政策と患者監視技術の倫理規制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル医薬採用研究','2017','micro','adoption','privacy_ethics_adoption','["Brown, M.T.", "Bussell, J.K.", "Doshi, J.A."]','["Brown & Bussell (2011) Medication adherence", "Doshi et al. (2016) Digital adherence"]','デジタルピル,服薬確認,患者監視,プライバシー倫理','digital pill,medication adherence,patient monitoring,privacy ethics'),
('inno_diff_349','ゲノム編集作物採用の社会受容研究（CRISPR）','Social Acceptance Research on CRISPR Genome-Edited Crop Adoption','CRISPR-Cas9で育種改良された農作物への消費者・農家・規制機関の採用態度を分析した研究群。GMとの違いの認識・規制区分・環境リスク評価・消費者教育効果が受容規定因として確認されている。','ゲノム編集農産物規制設計と食料システム政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','バイオテクノロジー採用研究','2020','micro','adoption','biotechnology_risk_acceptance','["Lassoued, R.", "Macall, D.", "Smyth, S.J."]','["Lassoued et al. (2021) CRISPR crops acceptance", "Smyth (2020) Gene editing governance"]','CRISPR,ゲノム編集作物,農業バイオテクノロジー,消費者受容','CRISPR,genome-edited crops,agricultural biotechnology,consumer acceptance'),
('inno_diff_350','サービスロボット採用のホスピタリティ研究','Hospitality Industry Research on Service Robot Adoption','ホテル・レストラン・空港でのフロントロボット・配膳ロボット・清掃ロボット採用を分析した研究群。顧客の温もりへの期待・ロボットの外見設計・サービス文化規範・コスト対効果が採用規定因として確認されている。COVID-19期における非接触需要の役割も研究されている。','ホスピタリティ産業のDX戦略とサービスロボット規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','サービスロボット採用研究','2018','meso','adoption','service_robot_adoption','["Ivanov, S.", "Webster, C.", "Grieve, R."]','["Ivanov et al. (2017) Robots in hospitality", "Webster & Ivanov (2020) Servicebot"]','サービスロボット,ホテルロボット,配膳ロボット,ホスピタリティDX','service robot,hotel robot,delivery robot,hospitality DX');
